 1	import React, { FC } from 'react';
 2	
 3	import { Button, ButtonVariant } from '@patternfly/react-core';
 4	import { getVMStatusIcon } from '@virtualmachines/utils';
 5	
 6	type StatusPopoverButtonProps = {
 7	  vmPrintableStatus: string;
 8	};
 9	
10	const StatusPopoverButton: FC<StatusPopoverButtonProps> = ({ vmPrintableStatus }) => {
11	  if (!vmPrintableStatus) return null;
12	
13	  const Icon = getVMStatusIcon(vmPrintableStatus);
14	
15	  return (
16	    <span>
17	      <Icon />{' '}
18	      <Button isInline variant={ButtonVariant.link}>
19	        {vmPrintableStatus}
20	      </Button>
21	    </span>
22	  );
23	};
24	
25	export default StatusPopoverButton;

